target.script:

var out = java.lang.System.out;
out.println("ANS-SYSOUT: target script running");
try {
  var igTemp = project.getProperty("ig.temp");
  out.println("ANS-SYSOUT: ig.temp = " + igTemp);

  out.println("ANS-SYSOUT: creating File object for languages.json...");
  var File = java.io.File;
  out.println("ANS-SYSOUT: java.io.File = " + File);
  var langDataFile = new java.io.File(igTemp + "/_data/languages.json");
  out.println("ANS-SYSOUT: langDataFile created, exists = " + langDataFile.exists());

  if (langDataFile.exists()) {
    out.println("ANS-SYSOUT: reading languages.json");
    var content = new java.lang.String(java.nio.file.Files.readAllBytes(langDataFile.toPath()), "UTF-8");
    out.println("ANS-SYSOUT: content = " + content);
    var pattern = java.util.regex.Pattern.compile('"code"\\s*:\\s*"([^"]+)"');
    var matcher = pattern.matcher(content);
    while (matcher.find()) {
      var lang = matcher.group(1);
      var dir = new java.io.File(igTemp + "/_includes/" + lang);
      out.println("ANS-SYSOUT: mkdirs " + dir.getAbsolutePath());
      var result = dir.mkdirs();
      out.println("ANS-SYSOUT: mkdirs result=" + result + " exists=" + dir.exists());
    }
  } else {
    out.println("ANS-SYSOUT: languages.json not found - dumping ig.* and lang* properties:");
    var props = project.getProperties();
    var keys = props.keySet().toArray();
    java.util.Arrays.sort(keys);
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i];
      var ks = "" + k;
      if (ks.indexOf("ig.") >= 0 || ks.toLowerCase().indexOf("lang") >= 0 || ks.toLowerCase().indexOf("locale") >= 0) {
        out.println("ANS-PROP: " + k + " = " + props.get(k));
      }
    }
  }
} catch(e) {
  java.lang.System.out.println("ANS-SYSOUT: ERROR = " + e);
  java.lang.System.out.println("ANS-SYSOUT: STACK = " + e.stack);
}
